let full_path = parts[1];
let (path, query_params) = match full_path.split_once('?') {
    Some((p, qs)) => (p.to_string(), parse_query_string(qs)),
    None => (full_path.to_string(), HashMap::new()),
};

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_with_query_params() {
        let raw = "GET /search?q=hello&page=2 HTTP/1.1\nHost: example.com";
        let req = Request::parse(raw).unwrap();
        assert_eq!(req.path, "/search");
        assert_eq!(req.query_params.get("q"), Some(&"hello".to_string()));
        assert_eq!(req.query_params.get("page"), Some(&"2".to_string()));
    }

    #[test]
    fn test_parse_without_query() {
        let raw = "GET /index HTTP/1.1";
        let req = Request::parse(raw).unwrap();
        assert_eq!(req.path, "/index");
        assert!(req.query_params.is_empty());
    }
}
